object AccountActor {
  case class Deposit(amount: BigDecimal)
  case class Withdraw(amount: BigDecimal)
  case class GetBalance(replyTo: ActorRef)
  case class Balance(balance: BigDecimal)
  case class TransactionResult(success: Boolean, message: String)
  
  def props(accountId: String): Props = Props(new AccountActor(accountId))
