class AccountActor(accountId: String) extends Actor {
  import AccountActor._
  
  private val balance = new AtomicReference[BigDecimal](BigDecimal(0))
  
  override def receive: Receive = {
    case Deposit(amount) =>
      if (amount <= BigDecimal(0)) {
        sender() ! TransactionResult(false, "Invalid deposit amount")
      } else {
        val currentBalance = balance.get()
        val newBalance = currentBalance + amount
        if (balance.compareAndSet(currentBalance, newBalance)) {
          sender() ! TransactionResult(true, "Deposit successful")
        } else {
          sender() ! TransactionResult(false, "Deposit failed due to concurrent update")
        }
      }
      
    case Withdraw(amount) =>
      if (amount <= BigDecimal(0)) {
        sender() ! TransactionResult(false, "Invalid withdrawal amount")
      } else {
        val currentBalance = balance.get()
        if (currentBalance < amount) {
          sender() ! TransactionResult(false, "Insufficient funds")
        } else {
          val newBalance = currentBalance - amount
          if (balance.compareAndSet(currentBalance, newBalance)) {
            sender() ! TransactionResult(true, "Withdrawal successful")
          } else {
            sender() ! TransactionResult(false, "Withdrawal failed due to concurrent update")
